   input clk,
   input rst,
   output [3:0] count,
   output [3:0] countbar
   );

   reg q0, q1, q2, q3;

   assign count[0] = q0;
   assign countbar[0] = ~q0;
   assign count[1] = q1;
   assign countbar[1] = ~q1;
   assign count[2] = q2;
   assign countbar[2] = ~q2;
   assign count[3] = q3;
   assign countbar[3] = ~q3;

   always @ (posedge clk or posedge rst) begin
      if (rst) begin
         q0 <= 1'b0;
         q1 <= 1'b0;
         q2 <= 1'b0;
         q3 <= 1'b0;
      end
      else begin
         q0 <= countbar[0];
         q1 <= countbar[1] & q0;
         q2 <= countbar[2] & q1;
         q3 <= countbar[3] & q2;
      end
   end 

endmodule

