parameter AW = 14; 
  parameter DW = 32; 
  parameter WED = DW/8; 
  parameter MD = 1<<AW; 
  input clk; 
  input en; 
  input [WED-1:0] wen; 
  input [AW-1:0] addr; 
  input [DW-1:0] din; 
  output [DW-1:0] dout; 
 `ifdef TARGET_CLEAN 
  reg [DW-1:0] ram [MD-1:0]; 
  reg [DW-1:0] rd_data; 
  reg [DW-1:0] dout; 
  always @ (posedge clk) 
  if(en) 
  dout[DW-1:0] <= ram[addr[AW-1:0]]; 
  generate 
  genvar i; 
  for (i = 0; i < WED; i = i+1) begin: gen_ram 
  always @(posedge clk) 
  begin 
  if (wen[i] & en) 
  ram[addr[AW-1:0]][(i+1)*8-1:i*8] <= din[(i+1)*8-1:i*8]; 
  end 
  end 
  endgenerate 
 `elsif TARGET_XILINX 
 `elsif TARGET_ALTERA 
 `endif 
 endmodule

