      3'b100: begin
        compute_input_tm_cnt = 1;
      end  // 3'b100 

      3'b101: begin
        compute_input_tm_cnt = 2;
      end  // 3'b101 

      3'b110: begin
        compute_input_tm_cnt = 2;
      end  // 3'b110 

      3'b111: begin
        compute_input_tm_cnt = 3;
      end  // 3'b111 

    endcase  // switch_for_mux
  end



