module origen_175695(
    input [9:0] fifo4_out, fifo5_out, fifo6_out, fifo7_out,
    output reg [9:0] fifo0_i, fifo1_i, fifo2_i, fifo3_i,
    output reg push0, push1, push2, push3,
    output reg pop4, pop5, pop6, pop7,
    output reg reset, clk
);

reg [9:0] fifo0_is, fifo1_is, fifo2_is, fifo3_is;
reg push0s, push1s, push2s, push3s;
reg pop4s, pop5s, pop6s, pop7s;
reg reset_n;

initial begin
    fifo0_is = 0; fifo1_is = 0; fifo2_is = 0; fifo3_is = 0;
    push0s = 0; push1s = 0; push2s = 0; push3s = 0;
    pop4s = 0; pop5s = 0; pop6s = 0; pop7s = 0;
    reset_n = 0;
end

always #1 clk = ~clk;

initial begin
    reset = 1;
    #15 reset_n = 1;
    #10 repeat (8) begin
        fifo0_is = $random; fifo1_is = $random; fifo2_is = $random; fifo3_is = $random;
        push0s = 1; push1s = 1; push2s = 1; push3s = 1;
        #2;
    end
    push0s = 0; push1s = 0; push2s = 0; push3s = 0;
    repeat (8) begin
        pop4s = 1; pop5s = 1; pop6s = 1; pop7s = 1;
        #2 pop4s = 0; pop5s = 0; pop6s = 0; pop7s = 0;
    end
    #100 $finish;
end

always @(*) begin
    fifo0_i = fifo0_is;
    fifo1_i = fifo1_is;
    fifo2_i = fifo2_is;
    fifo3_i = fifo3_is;
    push0 = push0s;
    push1 = push1s;
    push2 = push2s;
    push3 = push3s;
    pop4 = pop4s;
    pop5 = pop5s;
    pop6 = pop6s;
    pop7 = pop7s;
    reset = ~reset_n;
end

endmodule

