  input clk; 
  reg[6:0] ul; 
  reg[6:0] vl; 
  assign texelselect = ul[1:0] ; 
  always @(posedge clk) 
  begin 
  if (enable == 1'b1) 
  begin 
  ul <= u ; 
  vl <= v ; 
  end 
  else 
  begin 
  ul <= ul ; 
  vl <= vl ; 
  end 
  case (factor) 
