module origen_045966 (
    input wire mosi,
    input wire sclk,
    input wire cs,
    output wire miso
);

    // Internal registers
    reg [7:0] internal_regs [45:0];

    // State machine states
    localparam AWAIT = 3'd0, READ_CMD = 3'd1, READ_ADDR = 3'd2, 
               WRITE_CMD = 3'd3, WRITE_ADDR = 3'd4, WRITE_DATA = 3'd5;

    reg [2:0] state;
    reg [7:0] shift_in, shift_out;
    reg [2:0] bit_count;
    reg [7:0] rw_addr;
    reg miso_reg;

    // Tri-state buffer for miso
    assign miso = cs ? 1'bz : miso_reg;

    // Initialize some registers with predefined values
    initial begin
        internal_regs[0] = 8'hA5;
        internal_regs[1] = 8'h5A;
        state = AWAIT;
    end

    always @(posedge sclk or posedge cs) begin
        if (cs) begin
            state <= AWAIT;
            bit_count <= 0;
        end else begin
            case (state)
                AWAIT: begin
                    state <= READ_CMD;
                    shift_in <= {shift_in[6:0], mosi};
                    bit_count <= bit_count + 1;
                end

                READ_CMD: begin
                    shift_in <= {shift_in[6:0], mosi};
                    if (bit_count == 3'd7) begin
                        bit_count <= 0;
                        case (shift_in)
                            8'h0A: state <= WRITE_ADDR;
                            8'h0B: state <= READ_ADDR;
                            default: state <= AWAIT;
                        endcase
                    end else begin
                        bit_count <= bit_count + 1;
                    end
                end

                READ_ADDR: begin
                    shift_in <= {shift_in[6:0], mosi};
                    if (bit_count == 3'd7) begin
                        rw_addr <= shift_in;
                        shift_out <= internal_regs[shift_in];
                        state <= READ_CMD;
                        bit_count <= 0;
                    end else begin
                        bit_count <= bit_count + 1;
                    end
                    miso_reg <= shift_out[7];
                    shift_out <= {shift_out[6:0], 1'b0};
                end

                WRITE_ADDR: begin
                    shift_in <= {shift_in[6:0], mosi};
                    if (bit_count == 3'd7) begin
                        rw_addr <= shift_in;
                        state <= WRITE_DATA;
                        bit_count <= 0;
                    end else begin
                        bit_count <= bit_count + 1;
                    end
                end

                WRITE_DATA: begin
                    shift_in <= {shift_in[6:0], mosi};
                    if (bit_count == 3'd7) begin
                        internal_regs[rw_addr] <= shift_in;
                        state <= AWAIT;
                        bit_count <= 0;
                    end else begin
                        bit_count <= bit_count + 1;
                    end
                end

                default: state <= AWAIT;
            endcase
        end
    end

endmodule

