module autovcoder_071115 (
    input clk_ext,  // 27MHz for MiST, 50MHz for Neptuno

    // PLL outputs
    output clk96,
    output clk48,
    output clk24,
    output clk6,
    output pll_locked,

    // System clocks
    output clk_sys,
    output clk_rom,
    output SDRAM_CLK,

    // reset signals
    input  game_rst,
    output rst96,
    output rst48,
    output rst24,
    output rst6
);

`ifndef JTFRAME_PLL
  `define JTFRAME_PLL jtframe_pll6000
`endif

`ifdef JTFRAME_SDRAM96
  `define JTFRAME_GAMEPLL jtframe_pllgame96
`else
  `define JTFRAME_GAMEPLL jtframe_pllgame
`endif

  wire pll0_lock, pll1_lock, pll_base, clk27;

  assign pll_locked = pll0_lock & pll1_lock;

`ifdef NEPTUNO
  pll_neptuno u_pllneptuno (
      .inclk0(clk_ext),
      .c0    (clk27),
      .locked(pll0_lock)
  );
`else
  assign clk27 = clk_ext;
  assign pll0_lock = 1;
`endif

  `JTFRAME_PLL u_basepll (
      .inclk0(clk27),
      .c0    (pll_base),
`ifdef SIMULATION  // This prevents a warning that we can ignore
      .c1    (),
      .c2    (),
      .c3    (),
      .c4    (),
`endif
      .locked()
  );

  // clk_rom is used for SDRAM access
  // clk_sys is for video
  // clk96, clk24 and clk6 inputs to the core can be enabled via macros
  `JTFRAME_GAMEPLL u_pll_game (
      .inclk0(pll_base),
      .c0    (clk96),
      .c1    (clk48),      // 48 MHz
      .c2    (SDRAM_CLK),  // 96 or 48 MHz shifted
      .c3    (clk24),
      .c4    (clk6),
      .locked(pll1_lock)
  );

`ifdef JTFRAME_SDRAM96
  assign clk_rom = clk96;
`else
  assign clk_rom = clk48;
`endif
`ifdef JTFRAME_CLK96
  assign clk_sys = clk96;  // it is possible to use clk48 instead but
  // video mixer doesn't work well in HQ mode
`else
  assign clk_sys = clk_rom;
`endif

  jtframe_rst_sync u_reset96 (
      .rst     (game_rst),
      .clk     (clk96),
      .rst_sync(rst96)
  );

  jtframe_rst_sync u_reset48 (
      .rst     (game_rst),
      .clk     (clk48),
      .rst_sync(rst48)
  );

  jtframe_rst_sync u_reset24 (
      .rst     (game_rst),
      .clk     (clk24),
      .rst_sync(rst24)
  );

  jtframe_rst_sync u_reset6 (
      .rst     (game_rst),
      .clk     (clk6),
      .rst_sync(rst6)
  );


endmodule

