            4'h8 : char_addr_o = 7'h45;     
            4'h9 : char_addr_o = 7'h00;     
            4'hA : char_addr_o = 7'h4F;     
            4'hB : char_addr_o = 7'h56;     
            4'hC : char_addr_o = 7'h45;     
            default : char_addr_o = 7'h52;  
        endcase
    end

    always @* begin
        text_rgb = 12'h0FF;     

        if(score_on) begin
            char_addr = char_addr_s;
            row_addr = row_addr_s;
            bit_addr = bit_addr_s;
            if(ascii_bit)
                text_rgb = 12'hF00; 
        end else begin 
            char_addr = char_addr_o;
            row_addr = row_addr_o;
            bit_addr = bit_addr_o;
            if(ascii_bit)
                text_rgb = 12'hF00; 
        end        
    end

    assign text_on = {score_on, logo_on, rule_on, over_on};
    assign rom_addr = {char_addr, row_addr};
    assign ascii_bit = ascii_word[~bit_addr];

endmodule

