module HexTo7Segment(hex, les, point, seg);
    input [3:0] hex;
    input les;
    input point;
    output [7:0] seg;

    reg [7:0] seg;

    always @(*) begin
        case (hex)
            4'h0: seg = 8'b11000000;
            4'h1: seg = 8'b11111001;
            4'h2: seg = 8'b10100100;
            4'h3: seg = 8'b10110000;
            // ... (additional cases for other hex values)
            4'hF: seg = 8'b10001110;
            default: seg = 8'b11111111;
        endcase

        if (les) 
            seg = ~seg;

        if (point) 
            seg[7] = 0;
    end
endmodule

