  // define constants
  localparam MODULE_NAME = "IOBUF_INTERMDISABLE";

  wire ts, out_val;
  wire T_OR_IBUFDISABLE;

  tri0 GTS = glbl.GTS;

  or O1 (ts, GTS, T);
  bufif0 T1 (IO, I, ts);

  //    buf B1 (O, IO);

  initial begin


    case (IBUF_LOW_PWR)

      "FALSE", "TRUE": ;
