  assign unxunused_resetxx2 = 1'b1;

  // Synchronizer for vs_udr
  reg sync_udr_ff1, sync_udr_ff2;
  always @(posedge clk) begin
    if (~unxunused_resetxx2) begin
      sync_udr_ff1 <= 1'b0;
      sync_udr_ff2 <= 1'b0;
    end else begin
      sync_udr_ff1 <= vs_udr;
      sync_udr_ff2 <= sync_udr_ff1;
    end
  end
  assign sync_udr = sync_udr_ff2;

  assign unxunused_resetxx3 = 1'b1;

  // Synchronizer for vs_uir
  reg sync_uir_ff1, sync_uir_ff2;
  always @(posedge clk) begin
    if (~unxunused_resetxx3) begin
      sync_uir_ff1 <= 1'b0;
      sync_uir_ff2 <= 1'b0;
    end else begin
      sync_uir_ff1 <= vs_uir;
      sync_uir_ff2 <= sync_uir_ff1;
    end
  end
  assign sync_uir = sync_uir_ff2;

  always @(posedge clk) begin
    sync2_udr <= sync_udr;
    update_jdo_strobe <= sync_udr & ~sync2_udr;
    enable_action_strobe <= update_jdo_strobe;
    sync2_uir <= sync_uir;
    jxuir <= sync_uir & ~sync2_uir;
  end

  assign take_action_ocimem_a = enable_action_strobe && (ir == 2'b00) && 
    ~jdo[35] && jdo[34];

  assign take_no_action_ocimem_a = enable_action_strobe && (ir == 2'b00) && 
    ~jdo[35] && ~jdo[34];

  assign take_action_ocimem_b = enable_action_strobe && (ir == 2'b00) && 
    jdo[35];

  assign take_action_tracemem_a = enable_action_strobe && (ir == 2'b01) &&
    ~jdo[37] && 
    jdo[36];

  assign take_no_action_tracemem_a = enable_action_strobe && (ir == 2'b01) &&
    ~jdo[37] && 
    ~jdo[36];

  assign take_action_tracemem_b = enable_action_strobe && (ir == 2'b01) &&
    jdo[37];

  assign take_action_break_a = enable_action_strobe && (ir == 2'b10) && 
