module autovcoder_112211 (
    // Input signals
    mode,
    W_0,
    V_GS_0,
    V_DS_0,
    W_1,
    V_GS_1,
    V_DS_1,
    W_2,
    V_GS_2,
    V_DS_2,
    W_3,
    V_GS_3,
    V_DS_3,
    W_4,
    V_GS_4,
    V_DS_4,
    W_5,
    V_GS_5,
    V_DS_5,
    // Output signals
    out_n
);

  //================================================================
  //   INPUT AND OUTPUT DECLARATION                         
  //================================================================
  input [2:0] W_0, V_GS_0, V_DS_0;
  input [2:0] W_1, V_GS_1, V_DS_1;
  input [2:0] W_2, V_GS_2, V_DS_2;
  input [2:0] W_3, V_GS_3, V_DS_3;
  input [2:0] W_4, V_GS_4, V_DS_4;
  input [2:0] W_5, V_GS_5, V_DS_5;
  input [1:0] mode;
  //output [8:0] out_n;         							// use this if using continuous assignment for out_n  // Ex: assign out_n = XXX;
  output reg [9:0] out_n; 								// use this if using procedure assignment for out_n   // Ex: always@(*) begin out_n = XXX; end

  //================================================================
  //    Wire & Registers 
  //================================================================
  // Declare the wire/reg you would use in your circuit
  // remember 
  // wire for port connection and cont. assignment
  // reg for proc. assignment
  wire [7:0] I_0, I_1, I_2, I_3, I_4, I_5;
  wire [7:0] G_0, G_1, G_2, G_3, G_4, G_5;
  reg [7:0] IG_0, IG_1, IG_2, IG_3, IG_4, IG_5;
  reg [7:0] IG0, IG1, IG2, IG3, IG4, IG5;
  wire [7:0] IG_out0, IG_out1, IG_out2;
  reg [6:0] IG_out_div0, IG_out_div1, IG_out_div2;
  reg [9:0] op0, op1, op2, out_n_med;

  //================================================================
  //    DESIGN
  //================================================================
  // --------------------------------------------------
  // write your design here
  // --------------------------------------------------
  CALCULATE cal0 (
      .W(W_0),
      .V_GS(V_GS_0),
      .V_DS(V_DS_0),
      .I(I_0),
      .G(G_0)
  );
  CALCULATE cal1 (
      .W(W_1),
      .V_GS(V_GS_1),
      .V_DS(V_DS_1),
      .I(I_1),
      .G(G_1)
  );
  CALCULATE cal2 (
      .W(W_2),
      .V_GS(V_GS_2),
      .V_DS(V_DS_2),
      .I(I_2),
      .G(G_2)
  );
  CALCULATE cal3 (
      .W(W_3),
      .V_GS(V_GS_3),
      .V_DS(V_DS_3),
      .I(I_3),
      .G(G_3)
  );
  CALCULATE cal4 (
      .W(W_4),
      .V_GS(V_GS_4),
      .V_DS(V_DS_4),
      .I(I_4),
      .G(G_4)
  );
  CALCULATE cal5 (
      .W(W_5),
      .V_GS(V_GS_5),
      .V_DS(V_DS_5),
      .I(I_5),
      .G(G_5)
  );

  PICK pick (
      .in0 (IG0),
      .in1 (IG1),
      .in2 (IG2),
      .in3 (IG3),
      .in4 (IG4),
      .in5 (IG5),
      .out0(IG_out0),
      .out1(IG_out1),
      .out2(IG_out2),
      .mode(mode[1])
  );

  always @(*) begin
    if (mode[0] == 0) begin
      IG_0 = G_0;
      IG_1 = G_1;
      IG_2 = G_2;
      IG_3 = G_3;
      IG_4 = G_4;
      IG_5 = G_5;
    end else begin
      IG_0 = I_0;
      IG_1 = I_1;
      IG_2 = I_2;
      IG_3 = I_3;
      IG_4 = I_4;
      IG_5 = I_5;
    end

    if (mode[1] == 0) begin
      IG0 = ~IG_0;
      IG1 = ~IG_1;
      IG2 = ~IG_2;
      IG3 = ~IG_3;
      IG4 = ~IG_4;
      IG5 = ~IG_5;
    end else begin
      IG0 = IG_0;
      IG1 = IG_1;
      IG2 = IG_2;
      IG3 = IG_3;
      IG4 = IG_4;
      IG5 = IG_5;
    end

    IG_out_div0 = IG_out0 / 3;
    IG_out_div1 = IG_out1 / 3;
    IG_out_div2 = IG_out2 / 3;

    if (mode[0] == 0) begin
      op0 = IG_out_div0;
      op1 = IG_out_div1;
      op2 = IG_out_div2;
    end else begin
      op0 = 2 * IG_out_div0 + IG_out_div0;
      op1 = 4 * IG_out_div1;
      op2 = 4 * IG_out_div2 + IG_out_div2;
    end

    out_n = op0 + op1 + op2;
  end

endmodule

