    input wire rst_n,
    input wire tx_done,
    output reg tx_en,
    output reg [23:0] RGB
);

    reg [31:0] cnt;
    reg [23:0] RGB_reg [4:0];
    reg [3:0] k;
    reg tx_en_r;
    reg tx_done_r0;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            cnt <= 32'd0;
            k <= 4'd0;
            tx_en_r <= 1'b0;
            tx_done_r0 <= 1'b0;
            RGB <= 24'd0;
