            RGB_reg[2] <= 24'h0000FF;
            RGB_reg[3] <= 24'hFFFF00;
            RGB_reg[4] <= 24'h00FFFF;
        end else begin
            tx_done_r0 <= tx_done;

            if (cnt < 32'd14999) begin
                cnt <= cnt + 1'b1;
            end

            if (cnt == 32'd14999 && tx_done) begin
                tx_en_r <= 1'b1;
            end

            if (tx_en_r && !tx_done_r0 && tx_done) begin
                RGB <= RGB_reg[k];
                if (k == 4'd4) begin
                    k <= 4'd0;
                    tx_en_r <= 1'b0;
                end else begin
                    k <= k + 1'b1;
                end
                cnt <= 32'd0;
            end
        end
    end

    always @(*) begin
        tx_en = tx_en_r;
    end

