module origen_150915 #(
    parameter H_DISPLAY = 640,    // Horizontal display width
    parameter H_FRONT = 16,       // Horizontal front porch
    parameter H_SYNC = 96,        // Horizontal sync pulse width
    parameter H_BACK = 48,        // Horizontal back porch
    parameter V_DISPLAY = 480,    // Vertical display height
    parameter V_BOTTOM = 10,      // Vertical front porch
    parameter V_SYNC = 2,         // Vertical sync pulse width
    parameter V_TOP = 33          // Vertical back porch
) (
    input wire clk,
    output wire hsync,
    output wire vsync,
    output wire display_on,
    output wire [9:0] hpos,
    output wire [9:0] vpos
);

    reg [9:0] h_count, v_count;
    wire clk_25;

    // Generate 25 MHz clock from input clock
    assign clk_25 = clk;

    // Horizontal position counter
    always @(posedge clk_25) begin
        if (h_count == (H_DISPLAY + H_FRONT + H_SYNC + H_BACK - 1)) begin
            h_count <= 0;
        end else begin
            h_count <= h_count + 1;
        end
    end

    // Vertical position counter
    always @(posedge clk_25) begin
        if (h_count == (H_DISPLAY + H_FRONT + H_SYNC + H_BACK - 1)) begin
            if (v_count == (V_DISPLAY + V_BOTTOM + V_SYNC + V_TOP - 1)) begin
                v_count <= 0;
            end else begin
                v_count <= v_count + 1;
            end
        end
    end

    // Horizontal sync signal
    assign hsync = (h_count >= (H_DISPLAY + H_FRONT)) && (h_count < (H_DISPLAY + H_FRONT + H_SYNC));

    // Vertical sync signal
    assign vsync = (v_count >= (V_DISPLAY + V_BOTTOM)) && (v_count < (V_DISPLAY + V_BOTTOM + V_SYNC));

    // Display on signal
    assign display_on = (h_count < H_DISPLAY) && (v_count < V_DISPLAY);

    // Output position signals
    assign hpos = h_count;
    assign vpos = v_count;

endmodule

