    else begin
        hsyncCounter <= hsyncCounter + 1;
        if (hsyncCounter == 800) begin
            hsyncCounter <= 0;
            hNext <= 1;
        end
        else begin
            hNext <= 0;
        end

        if (hNext) begin
            vsyncCounter <= vsyncCounter + 1;
            if (vsyncCounter == 525) begin
                vsyncCounter <= 0;
                vNext <= 1;
            end
            else begin
                vNext <= 0;
