assign green = (vsyncCounter >= 0 && vsyncCounter <= 479) ? 4'b1111 : 4'b0000;
assign blue = (hsyncCounter >= 0 && hsyncCounter <= 639 && vsyncCounter >= 0 && vsyncCounter <= 479) ? 4'b1111 : 4'b0000;

