module origen_042774 (
    input wire clk,
    input wire rst_n,
    input wire key_in,
    output wire key_out
);

reg key_in_dly1, key_in_dly2;
reg [17:0] count_debouncer;
reg key_out_r, key_out_dly1_r;

// Input synchronization
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        key_in_dly1 <= 1'b0;
        key_in_dly2 <= 1'b0;
    end else begin
        key_in_dly1 <= key_in;
        key_in_dly2 <= key_in_dly1;
    end
end

// Debounce counter
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        count_debouncer <= 18'd0;
    end else if (key_in_dly2) begin
        count_debouncer <= 18'd0;
    end else if (count_debouncer < 18'd260000) begin
        count_debouncer <= count_debouncer + 1'b1;
    end
end

// Debounced output logic
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        key_out_r <= 1'b0;
    end else if (count_debouncer == 18'd250000) begin
        key_out_r <= 1'b1;
    end else if (count_debouncer == 18'd260000) begin
        key_out_r <= 1'b0;
    end
end

// Edge detection
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        key_out_dly1_r <= 1'b0;
    end else begin
        key_out_dly1_r <= key_out_r;
    end
end

assign key_out = key_out_r & ~key_out_dly1_r;

endmodule

