files.origen_133771.v:
module origen_133771 #(
    parameter N = 8,
    parameter WIDTH = 16,
    parameter FRAC_BITS = 14,
    parameter MU = 16'h0004,  // 0.0001 in fixed-point
    parameter DELTA = 16'h4000  // 1.0 in fixed-point
)(
    input wire clk,
    input wire rst,
    input wire signed [WIDTH-1:0] x,
    input wire signed [WIDTH-1:0] d,
    output wire signed [WIDTH-1:0] y,
    output wire signed [WIDTH-1:0] e
);

    reg signed [WIDTH-1:0] w [0:N-1];
    reg signed [WIDTH-1:0] x_delay [0:N-1];
    reg signed [WIDTH-1:0] y_reg, e_reg;

    integer i;

    // LMS algorithm implementation
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            for (i = 0; i < N; i = i + 1) begin
                w[i] <= 0;
                x_delay[i] <= 0;
            end
            y_reg <= 0;
            e_reg <= 0;
        end else begin
            // Shift input samples
            for (i = N-1; i > 0; i = i - 1) begin
                x_delay[i] <= x_delay[i-1];
            end
            x_delay[0] <= x;

            // Compute output
            y_reg <= 0;
            for (i = 0; i < N; i = i + 1) begin
                y_reg <= y_reg + ((w[i] * x_delay[i]) >>> FRAC_BITS);
            end

            // Compute error
            e_reg <= d - y_reg;

            // Update coefficients
            for (i = 0; i < N; i = i + 1) begin
                w[i] <= w[i] + ((MU * e_reg * x_delay[i]) >>> FRAC_BITS);
            end
        end
    end

    assign y = y_reg;
    assign e = e_reg;

endmodule

files.origen_197108.v:
module origen_197108(
    input clk,
    input rst_n,
    input data_in,
    input data_in_valid,
    output reg [15:0] data_out,
    output reg data_out_valid
);

reg [15:0] ff;
wire [15:0] next_ff;

// CRC polynomial: x^16 + x^12 + x^5 + 1
assign next_ff = {ff[14:0], data_in} ^ (ff[15] ? 16'h8005 : 16'h0000);

reg [1:0] state;
parameter INIT = 2'b00, WAIT = 2'b01, CALC = 2'b10;

reg [3:0] out_ptr;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        state <= INIT;
        ff <= 16'hFFFF;
        out_ptr <= 4'b0;
        data_out <= 16'b0;
        data_out_valid <= 1'b0;
    end
    else begin
        case (state)
            INIT: begin
                ff <= 16'hFFFF;
                state <= WAIT;
            end
            WAIT: begin
                if (data_in_valid) begin
                    state <= CALC;
                end
            end
            CALC: begin
                ff <= next_ff;
                data_out <= ~ff[out_ptr];
                data_out_valid <= 1'b1;
                out_ptr <= out_ptr + 1'b1;
                if (out_ptr == 4'b1111) begin
                    state <= INIT;
                    data_out_valid <= 1'b0;
                end
            end
            default: state <= INIT;
        endcase
    end
end

endmodule

