            );
        end
    endgenerate

endmodule

module ripple_carry_adder_32bit(
    input [31:0] a,
    input [31:0] b,
    input cin,
    output [31:0] sum,
    output cout
);

    wire [32:0] carry;
    assign carry[0] = cin;

