module ALUU (
    input wire [3:0] ACCU,
    input wire [3:0] BUFFER,
    input wire [2:0] S,
    output reg [3:0] SAL,
    output wire C,
    output wire ZERO
);
    reg [4:0] OF;

    always @(*) begin
        case (S)
            3'b000: OF = {1'b0, ACCU};
            3'b001: OF = {1'b0, ACCU} - {1'b0, BUFFER};
            3'b010: OF = {1'b0, BUFFER};
            3'b011: OF = {1'b0, ACCU} + {1'b0, BUFFER};
            3'b100: OF = {1'b0, ~(ACCU | BUFFER)};
            default: OF = 5'b00000;
        endcase
        SAL = OF[3:0];
    end

    assign C = OF[4];
    assign ZERO = (SAL == 4'b0000);
endmodule

module operacional (
    input wire clk,
    input wire rst,
    input wire ENA,
    input wire ENB,
    input wire ENC,
    input wire [2:0] S,
    input wire [3:0] OPRND,
    output wire [3:0] SAL,
    output wire [3:0] BUFFER_OUT,
    output wire [3:0] ALU_OUT,
    output wire [3:0] ACCU_OUT,
    output wire C,
    output wire ZERO
);
    wire [3:0] accu_to_alu;
    wire [3:0] buffer_to_alu;
    wire [3:0] alu_to_accu;

