        .clk(clk),
        .rst(rst),
        .ena(ENA),
        .d(alu_to_accu),
        .q(accu_to_alu)
    );

    BT buffer (
        .I(OPRND),
        .EN(ENB),
        .Y(buffer_to_alu)
    );

    ALUU alu (
        .ACCU(accu_to_alu),
        .BUFFER(buffer_to_alu),
        .S(S),
        .SAL(alu_to_accu),
        .C(C),
        .ZERO(ZERO)
    );

    BT output_buffer (
        .I(alu_to_accu),
        .EN(ENC),
        .Y(SAL)
    );

    assign BUFFER_OUT = buffer_to_alu;
    assign ALU_OUT = alu_to_accu;
    assign ACCU_OUT = accu_to_alu;
endmodule

